import React, { useContext } from 'react';
import { BrowserRouter, Routes, Route, Link } from 'react-router-dom';
import { AppProvider, AppContext } from './context/AppContext';

// Импорт всех страниц
import CatalogPage from './pages/CatalogPage';
import LoginPage from './pages/LoginPage';
import ProfilePage from './pages/ProfilePage';
import AdminPage from './pages/AdminPage';

// Импорт стилей
import './styles/global.css';

const Header = () => {
  const { user, setUser } = useContext(AppContext);

  return (
    <nav style={{ 
      background: '#1a1a1a', 
      padding: '1rem 5%', 
      display: 'flex', 
      justifyContent: 'space-between', 
      alignItems: 'center',
      boxShadow: '0 2px 10px rgba(0,0,0,0.3)'
    }}>
      <Link to="/" style={{ color: 'white', fontSize: '1.5rem', fontWeight: 'bold', textDecoration: 'none' }}>
        SNEAKER SHOP
      </Link>
      
      <div style={{ display: 'flex', gap: '25px', alignItems: 'center' }}>
        <Link to="/" style={{ color: 'white', textDecoration: 'none' }}>Каталог</Link>
        
        {user ? (
          <>
            <Link to="/profile" style={{ color: 'white', textDecoration: 'none' }}>Мои заказы</Link>
            
            {/* ПРОВЕРКА РОЛИ АДМИНА */}
            {user.role === 'admin' && (
              <Link to="/admin" style={{ 
                color: '#ffcc00', 
                fontWeight: 'bold', 
                textDecoration: 'none',
                border: '1px solid #ffcc00',
                padding: '5px 10px',
                borderRadius: '5px'
              }}>
                Админ-панель
              </Link>
            )}
            
            <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
              <span style={{ color: '#888', fontSize: '0.8rem' }}>
                ({user.username} | {user.role})
              </span>
              <button 
                onClick={() => {
                  setUser(null);
                  window.location.href = '/'; // Редирект на главную при выходе
                }} 
                style={{ 
                  background: '#dc3545', 
                  color: 'white', 
                  border: 'none', 
                  padding: '5px 12px', 
                  borderRadius: '4px', 
                  cursor: 'pointer',
                  fontSize: '14px'
                }}
              >
                Выйти
              </button>
            </div>
          </>
        ) : (
          <Link to="/login" style={{ 
            background: '#007bff', 
            color: 'white', 
            padding: '8px 20px', 
            borderRadius: '5px', 
            textDecoration: 'none' 
          }}>
            Вход
          </Link>
        )}
      </div>
    </nav>
  );
};

function App() {
  return (
    <AppProvider>
      <BrowserRouter>
        <div className="App">
          <Header />
          <div className="main-content">
            <Routes>
              <Route path="/" element={<CatalogPage />} />
              <Route path="/login" element={<LoginPage />} />
              <Route path="/profile" element={<ProfilePage />} />
              <Route path="/admin" element={<AdminPage />} />
            </Routes>
          </div>
        </div>
      </BrowserRouter>
    </AppProvider>
  );
}

export default App;
